package com.example.presentations.auth.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.core.components.Validators
import com.example.domain.auth.usecases.LoginUseCase
import com.example.presentations.auth.state.LoginState
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

class LoginPageViewModel(
    private val loginUseCase: LoginUseCase
): ViewModel() {
    private val _state = MutableStateFlow(LoginState())
    val state = _state.asStateFlow()

    fun onEmailChange(email: String) {
        _state.update {
            it.copy(
                email = email,
                isFormValid = validateForm(email, it.password)
            )
        }
    }

    fun onPasswordChange(password: String) {
        _state.update {
            it.copy(
                password = password,
                isFormValid = validateForm(it.email, password)
            )
        }
    }

    private fun validateForm(email: String, password: String): Boolean {
        return Validators.isNotEmpty(email).isValid &&
                Validators.isValidEmail(email).isValid &&
                Validators.isNotEmpty(password).isValid &&
                Validators.isValidPassword(password).isValid
    }

    fun login() {
        val currentState = _state.value
        _state.update {
            it.copy(
                isLoading = true,
                error = null
            )
        }
        viewModelScope.launch {
            loginUseCase(currentState.email, currentState.password).fold(
                onSuccess = { data ->
                    _state.update {
                        it.copy(
                            isLoading = false,
                            error = null
                        )
                    }
                },
                onFailure = { error ->
                    _state.update {
                        it.copy(
                            isLoading = false,
                            error = error.message
                        )
                    }
                }
            )
        }
    }
}

package com.example.presentations.auth.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.core.components.Validators
import com.example.domain.auth.usecases.LoginUseCase
import com.example.presentations.auth.state.LoginState
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

class LoginPageViewModel(
    private val loginUseCase: LoginUseCase
): ViewModel() {
    private val _state = MutableStateFlow(LoginState())
    val state = _state.asStateFlow()

    fun onEmailChange(email: String) {
        _state.update {
            it.copy(
                email = email,
                isFormValid = validateForm(email, it.password)
            )
        }
    }

    fun onPasswordChange(password: String) {
        _state.update {
            it.copy(
                password = password,
                isFormValid = validateForm(it.email, password)
            )
        }
    }

    private fun validateForm(email: String, password: String): Boolean {
        return Validators.isNotEmpty(email).isValid &&
                Validators.isValidEmail(email).isValid &&
                Validators.isNotEmpty(password).isValid &&
                Validators.isValidPassword(password).isValid
    }

    fun login() {
        val currentState = _state.value
        _state.update {
            it.copy(
                isLoading = true,
                error = null,
                success = null
            )
        }
        viewModelScope.launch {
            loginUseCase(currentState.email, currentState.password).fold(
                onSuccess = { data ->
                    _state.update {
                        it.copy(
                            isLoading = false,
                            error = null,
                            success = data
                        )
                    }
                },
                onFailure = { error ->
                    _state.update {
                        it.copy(
                            isLoading = false,
                            error = error.message,
                            success = null
                        )
                    }
                }
            )
        }
    }

    fun clearSnackbarState() {
        _state.update { it.copy(error = null, success = null) }
    }
}

package com.example.domain.auth.usecases

import com.example.domain.auth.repository.AuthRepository

class SignUpUseCase(
    private val authRepository: AuthRepository
) {
    suspend operator fun invoke(username: String, password: String): Result<String> {
        return authRepository.register(username, password)
    }
}

package com.example.domain.auth.usecases

import com.example.domain.auth.entities.User
import com.example.domain.auth.repository.AuthRepository

class SignUpUseCase(
    private val authRepository: AuthRepository
) {
    suspend operator fun invoke(username: String, password: String): Result<User> {
        return authRepository.register(username, password)
    }
}
